INSERT INTO "notices" ("id","title","content","target","is_pinned","created_at") VALUES(2,'[공지] 4월부터 새로운 운영 시스템으로 전환됩니다',replace('안녕하세요, 타임오프클럽 스팟 운영자 여러분.\n4월 예약부터 새로운 운영 시스템을 도입합니다. \n변경되는 내용을 아래에 정리했으니 꼭 확인해 주세요. 기존에 노션으로 공유드렸던 운영 가이드 내용도 모두 이곳 공지사항으로 이전할 예정입니다. \n앞으로 모든 것은 이 사이트에서 진행 된다고 생각해주셔도 되어요.  \n\n1. 4인 미만도 세션 정상 진행\n멤버들이 예약 시 참석 인원 수와 선호 모드(스몰토크 / 사색)를 미리 확인할 수 있게 되었습니다. 이에 따라 4인 미만이어도 세션을 정상 진행합니다.\n\n2. 출석 체크 방식 안내\n타임오프클럽은 익명성을 보호하기 위해 핸드폰 번호 뒷자리로 출석을 확인합니다. \n멤버가 도착해서 주문할때 운영자 로그인, 참가자 체크 기능을 통해 번호 뒷자리를 확인해 체크해 주세요. 생각보다 쉬워요 :-) \n노쇼를 줄이기 위해 하나씩 방법을 모색하고 있습니다.\n\n3. 체험권 멤버 안내\n처음 방문하는 체험권 멤버도 시스템에서 확인이 가능합니다. 체험권 인원도 운영자 페이지에서 확인이 가능합니다. \n타임오프클럽에 대해 익숙하지 않은 분들이 많으니 이용 방식(스마트폰 반납, 음료 구매 등) 을 친절하게 안내해 주시면 감사하겠습니다.\n\n4. 스몰토크 / 사색 모드별 자리 안내\n예약 시 선택한 모드에 따라 자리를 구분해서 안내해 주시면 감사하겠습니다. \n음료 주문을 받을 때 스마트폰은 보관함에 넣어주시면 됩니다.\n\n5. 세션 종료 10분 전 안내\n멤버들이 시간 확인을 원하는 경우가 많아, 종료 10분 전에만 한 번 안내해 주세요. \n혹은 스팟 내에서 시간을 확인할 수 있는 위치를 함께 알려주시면 좋을 것 같아요. \n\n추가로 궁금한 사항은 공지사항을 통해 안내드리겠습니다. 항상 함께해 주셔서 감사합니다.','\n',char(10)),'all',0,'2026-03-23 05:43:18');
INSERT INTO "notices" ("id","title","content","target","is_pinned","created_at") VALUES(3,'4월 추가 공지',replace('안녕하세요 😊 4월부터 변경되는 운영 방식을 추가로 안내드립니다.\n\n🗓️ 세션 운영\n이전에 안내 드린대로, 4인 미만이어도 세션이 열립니다. \n멤버들도 예약 전에 신청 인원과 활동 유형(스몰토크/사색)을 미리 확인할 수 있어서, 인원이 적더라도 혼동하거나 당황하는 일은 없을 거에요 :-)\n\n⚙️ 인원 조정 및 일정 관리\n세션별 참가 인원은 스팟 운영자 페이지에서 직접 조정하실 수 있습니다. \n부득이하게 진행이 어려운 일정이 생기시면 미리 알려주시면 해당 일정을 막아두겠습니다.\n\n🏠 공간 운영 제안\n타임오프클럽 진행시 공간 전체 대관 형태가 부담스러우신 경우, 세션 참가 인원만큼만 자리를 확보하고 나머지는 외부 손님을 받으셔도 됩니다.\n\n✅ 출석 체크\n세션 당일 참가자 체크 기능을 통해 참석 멤버 출석 확인을 부탁드립니다. 노쇼를 줄이고, 고정 인원을 확보하는 방법을 모색중입니다.\n\n감사합니다 🙏','\n',char(10)),'all',0,'2026-03-30 06:43:35');
INSERT INTO "notices" ("id","title","content","target","is_pinned","created_at") VALUES(4,'타임오프클럽 5월 안내',replace('안녕하세요, 타임오프클럽입니다 🌿\n5월부터 변화하는 운영 방식을 안내드립니다.\n사장님의 부담을 덜어드리기 위한 변경이니 꼭 확인 부탁드려요.\n\n━━━━━━━━━━━━━\n📢 5월부터 달라지는 점\n기존에는 매주 수요일, 일요일 세션을 모두 열어드리다 보니\n운영상 어려움이 있으셨을 것 같습니다.\n5월부터는 월 최소 2회 이상 (수요일 1회 + 일요일 1회)만\n오픈해 주시면 됩니다.\n\n- 최소 기준 : 월 2회 (수 1회 + 일 1회)\n- 많이 여실수록 멤버들의 참여 기회가 늘어나지만,\n- 스팟별 사정이 다르니 유연하게 조절하실 수 있도록 변경했습니다\n\n5월에는 스팟이 2군데 추가됩니다! \n\n━━━━━━━━━━━━━\n📅 세션 일정 설정 방법\n멤버들은 시작 월 1주 전부터 예약을 시작합니다.\n따라서 사장님께서는 시작 월 2주 전까지\n월 전체 세션 ON/OFF를 설정해 주시면 됩니다.\n세션별 인원 조정도 가능합니다.\n\n━━━━━━━━━━━━━\n💡 5월 멤버십 일정 예시\nㆍ 4월 3째주 → 사장님이 5월 세션 일정 ON/OFF 설정\nㆍ 4월 마지막주 → 멤버들이 5월 예약 시작\nㆍ 5월 → 세션 진행\n\n━━━━━━━━━━━━━\n5월 일정 설정 부탁드리고,\n궁금하신 점 있으시면 언제든 편하게 연락 주세요.\n감사합니다 🙏\n','\n',char(10)),'all',1,'2026-04-18 07:48:54');
