PRAGMA defer_foreign_keys=TRUE;
CREATE TABLE users (
  id INTEGER PRIMARY KEY AUTOINCREMENT, name TEXT NOT NULL UNIQUE, is_admin INTEGER DEFAULT 0, created_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE members (
  id INTEGER PRIMARY KEY AUTOINCREMENT, name TEXT NOT NULL, phone_last4 TEXT NOT NULL, is_active INTEGER DEFAULT 1,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME DEFAULT CURRENT_TIMESTAMP, active_months TEXT DEFAULT '', phone TEXT, email TEXT, age_gender TEXT, occupation TEXT, self_intro TEXT, reasons TEXT, expectation TEXT, smartstore_order_id TEXT, approval_status TEXT DEFAULT 'approved', onboarded_at DATETIME, agreements_at DATETIME, rejected_reason TEXT, UNIQUE(name, phone_last4)
);
CREATE TABLE spot_operators (
  id INTEGER PRIMARY KEY AUTOINCREMENT, name TEXT NOT NULL, spot_id TEXT NOT NULL UNIQUE, password TEXT NOT NULL, created_at DATETIME DEFAULT CURRENT_TIMESTAMP
, is_spot_active INTEGER DEFAULT 1, inactive_from TEXT, active_from TEXT);
CREATE TABLE reservations (
  id INTEGER PRIMARY KEY AUTOINCREMENT, user_name TEXT NOT NULL, date TEXT NOT NULL, spot TEXT NOT NULL,
  check_in_status TEXT DEFAULT 'unchecked', checked_at DATETIME, checked_by TEXT,
  confirmed INTEGER DEFAULT 0, confirmed_at DATETIME, mode TEXT DEFAULT 'smalltalk',
  memo TEXT DEFAULT '', energy TEXT DEFAULT 'normal',
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP, is_trial INTEGER DEFAULT 0, badge_checked INTEGER DEFAULT 0, UNIQUE(user_name, date)
);
CREATE TABLE reservation_logs (
  id INTEGER PRIMARY KEY AUTOINCREMENT, user_name TEXT NOT NULL, date TEXT NOT NULL, spot TEXT, action TEXT NOT NULL, created_at DATETIME DEFAULT CURRENT_TIMESTAMP
, phone_last4 TEXT);
CREATE TABLE waitlist (
  id INTEGER PRIMARY KEY AUTOINCREMENT, user_name TEXT NOT NULL, date TEXT NOT NULL, spot TEXT NOT NULL,
  position INTEGER DEFAULT 0, is_notified INTEGER DEFAULT 0, created_at DATETIME DEFAULT CURRENT_TIMESTAMP, UNIQUE(user_name, date, spot)
);
CREATE TABLE noshow_warnings (
  id INTEGER PRIMARY KEY AUTOINCREMENT, user_name TEXT NOT NULL, warning_level INTEGER DEFAULT 1, message TEXT, created_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE trial_tickets (
  id INTEGER PRIMARY KEY AUTOINCREMENT, code TEXT NOT NULL UNIQUE, name TEXT, phone_last4 TEXT,
  is_used INTEGER DEFAULT 0, used_at DATETIME, created_at DATETIME DEFAULT CURRENT_TIMESTAMP
, is_delivered INTEGER DEFAULT 0, delivered_at DATETIME);
CREATE TABLE feedbacks (
  id INTEGER PRIMARY KEY AUTOINCREMENT, user_name TEXT NOT NULL, date TEXT NOT NULL, spot TEXT NOT NULL,
  service_rating INTEGER DEFAULT 0, service_feedback TEXT, person_issue TEXT, general_comment TEXT, created_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE session_moments (
  id INTEGER PRIMARY KEY AUTOINCREMENT, user_name TEXT NOT NULL, date TEXT NOT NULL, spot TEXT NOT NULL,
  moment_text TEXT NOT NULL, is_anonymous INTEGER DEFAULT 1, created_at DATETIME DEFAULT CURRENT_TIMESTAMP, UNIQUE(user_name, date, spot)
);
CREATE TABLE notices (id INTEGER PRIMARY KEY AUTOINCREMENT, title TEXT NOT NULL, content TEXT NOT NULL, target TEXT DEFAULT 'all', is_pinned INTEGER DEFAULT 0, created_at DATETIME DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE reports (id INTEGER PRIMARY KEY AUTOINCREMENT, reporter_name TEXT NOT NULL, date TEXT NOT NULL, spot TEXT NOT NULL, description TEXT NOT NULL, person_description TEXT, status TEXT DEFAULT 'pending', admin_note TEXT, created_at DATETIME DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE settings (key TEXT PRIMARY KEY, value TEXT);
CREATE TABLE session_capacity (id INTEGER PRIMARY KEY AUTOINCREMENT, date TEXT NOT NULL, spot TEXT NOT NULL, max_capacity INTEGER DEFAULT 10, UNIQUE(date, spot));
CREATE TABLE operator_requests (id INTEGER PRIMARY KEY AUTOINCREMENT, user_name TEXT NOT NULL, spot TEXT, category TEXT DEFAULT 'general', content TEXT NOT NULL, is_read INTEGER DEFAULT 0, admin_reply TEXT, created_at DATETIME DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE closed_dates (id INTEGER PRIMARY KEY AUTOINCREMENT, date TEXT NOT NULL, spot TEXT, reason TEXT, created_at DATETIME DEFAULT CURRENT_TIMESTAMP, UNIQUE(date, spot));
CREATE TABLE spot_notices (id INTEGER PRIMARY KEY AUTOINCREMENT, spot TEXT NOT NULL UNIQUE, notice TEXT NOT NULL, updated_at DATETIME DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE reflection_logs (id INTEGER PRIMARY KEY AUTOINCREMENT, user_name TEXT NOT NULL, date TEXT NOT NULL, spot TEXT NOT NULL, activity TEXT, feeling TEXT, insight TEXT, next_time TEXT, created_at DATETIME DEFAULT CURRENT_TIMESTAMP, UNIQUE(user_name, date, spot));
CREATE TABLE push_subscriptions (id INTEGER PRIMARY KEY AUTOINCREMENT, user_name TEXT NOT NULL, endpoint TEXT NOT NULL UNIQUE, p256dh TEXT NOT NULL, auth TEXT NOT NULL, created_at DATETIME DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE notifications (id INTEGER PRIMARY KEY AUTOINCREMENT, user_name TEXT NOT NULL, title TEXT NOT NULL, body TEXT, type TEXT DEFAULT 'reminder', date TEXT, spot TEXT, is_read INTEGER DEFAULT 0, created_at DATETIME DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE member_badges (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  member_name TEXT NOT NULL,
  badge_type TEXT NOT NULL, -- 'explorer', 'adventurer', 'master', 'collector', 'first_timer', 'regular', 'consistent', 'social', 'meditation'
  earned_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  UNIQUE(member_name, badge_type)
);
CREATE TABLE member_spot_stats (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  member_name TEXT NOT NULL,
  spot TEXT NOT NULL,
  visit_count INTEGER DEFAULT 0,
  first_visit_date TEXT,
  last_visit_date TEXT,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  UNIQUE(member_name, spot)
);
CREATE TABLE conversation_topics (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    date TEXT NOT NULL, -- 세션 날짜 (YYYY-MM-DD)
    spot TEXT NOT NULL, -- 스팟 ID
    topic TEXT NOT NULL, -- 대화 주제 (최대 30자)
    category TEXT, -- 주제 카테고리 (nullable, 직접 작성 시 null)
    created_by TEXT NOT NULL, -- 주제를 연 멤버 이름
    created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
    UNIQUE(date, spot) -- 한 세션(날짜+스팟)에 주제 1개만
);
CREATE TABLE IF NOT EXISTS "urgent_notifications" (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  member_name TEXT NOT NULL,
  title TEXT NOT NULL,
  content TEXT NOT NULL,
  created_at TEXT NOT NULL,
  expires_at TEXT NOT NULL,
  is_read INTEGER DEFAULT 0
);
DELETE FROM sqlite_sequence;
CREATE INDEX idx_conversation_topics_date ON conversation_topics(date);
CREATE INDEX idx_conversation_topics_date_spot ON conversation_topics(date, spot);
CREATE INDEX idx_members_approval_status ON members(approval_status);
CREATE INDEX idx_members_smartstore_order ON members(smartstore_order_id);
CREATE INDEX idx_urgent_notifications_member ON urgent_notifications(member_name);
CREATE INDEX idx_urgent_notifications_expires ON urgent_notifications(expires_at);
CREATE INDEX idx_urgent_notifications_read ON urgent_notifications(is_read);
